// src/json-pointer.ts
function decodeSegment(segment) {
  return segment.replace(/~1/g, "/").replace(/~0/g, "~");
}
function readJsonPointer(value, pointer) {
  if (pointer === "")
    return { ok: true, value };
  if (!pointer.startsWith("/"))
    return { ok: false, error: `Invalid JSON Pointer: ${pointer}` };
  let current = value;
  const segments = pointer.slice(1).split("/").map(decodeSegment);
  const traversed = [];
  for (const segment of segments) {
    traversed.push(segment);
    const path4 = `/${traversed.join("/")}`;
    if (Array.isArray(current)) {
      if (!/^0$|^[1-9]\d*$/.test(segment)) {
        return { ok: false, error: `Missing path segment ${path4}: expected array index` };
      }
      const index = Number(segment);
      if (index < 0 || index >= current.length) {
        return { ok: false, error: `Missing path segment ${path4}` };
      }
      current = current[index];
      continue;
    }
    if (current && typeof current === "object") {
      const obj = current;
      if (!Object.prototype.hasOwnProperty.call(obj, segment)) {
        return { ok: false, error: `Missing path segment ${path4}` };
      }
      current = obj[segment];
      continue;
    }
    return { ok: false, error: `Missing path segment ${path4}: cannot traverse ${typeof current}` };
  }
  return { ok: true, value: current };
}

