  if (stat.status !== 0) {
    return {
      ok: false,
      error: (stat.stderr || stat.stdout || "").trim() || "git diff --stat failed"
    };
  }
  const names = spawnSync("git", ["-C", worktreePath, "diff", "--name-only", "--no-ext-diff", "HEAD"], { encoding: "utf-8" });
